import * as React from "react";
import type { SlotClassNames } from "../../lib/slot-class-names";
import { Field } from "@base-ui/react/field";
import { Select as SelectPrimitive } from "@base-ui/react/select";
import { type VariantProps } from "class-variance-authority";
import { Check, ChevronDown, X } from "lucide-react";
import { selectTriggerVariants, selectPopupVariants, selectItemVariants } from "./select.variants";
import { cn } from "../../lib/cn";

export type SelectClassNames = SlotClassNames<
  "base" | "trigger" | "value" | "popup" | "item" | "label" | "description" | "errorMessage"
>;

export interface SelectItemOption {
  value: string;
  label: string;
  description?: string;
  isDisabled?: boolean;
}

export interface SelectProps extends VariantProps<typeof selectTriggerVariants> {
  items: SelectItemOption[];
  value?: string | string[] | null;
  defaultValue?: string | string[] | null;
  onValueChange?: (value: string | string[] | null) => void;
  isMultiple?: boolean;
  placeholder?: string;
  label?: string;
  description?: string;
  errorMessage?: string;
  isInvalid?: boolean;
  isRequired?: boolean;
  isDisabled?: boolean;
  isReadOnly?: boolean;
  isClearable?: boolean;
  side?: "top" | "bottom" | "left" | "right";
  align?: "start" | "center" | "end";
  sideOffset?: number;
  className?: string;
  classNames?: SelectClassNames;
}

export const Select = React.forwardRef<HTMLButtonElement, SelectProps>(
  (
    {
      className,
      classNames,
      variant,
      color,
      size,
      radius,
      items,
      value,
      defaultValue,
      onValueChange,
      isMultiple = false,
      placeholder = "Select an option",
      label,
      description,
      errorMessage,
      isInvalid = false,
      isRequired = false,
      isDisabled = false,
      isReadOnly = false,
      isClearable = false,
      side = "bottom",
      align = "start",
      sideOffset = 4,
    },
    ref,
  ) => {
    const hasValue = isMultiple
      ? Array.isArray(value ?? defaultValue) && (value ?? defaultValue)!.length > 0
      : Boolean(value ?? defaultValue);

    return (
      <Field.Root
        invalid={isInvalid}
        disabled={isDisabled}
        className={cn("flex flex-col gap-1", classNames?.base, className)}
      >
        {label && (
          <Field.Label className={cn("text-sm font-medium", classNames?.label)}>
            {label}
            {isRequired && (
              <span className="text-danger-500 ml-0.5" aria-hidden="true">
                *
              </span>
            )}
          </Field.Label>
        )}

        <SelectPrimitive.Root
          value={value}
          defaultValue={defaultValue}
          onValueChange={onValueChange}
          multiple={isMultiple}
          disabled={isDisabled}
          readOnly={isReadOnly}
          required={isRequired}
        >
          <SelectPrimitive.Trigger
            ref={ref}
            className={cn(
              selectTriggerVariants({ variant, color, size, radius, isInvalid }),
              classNames?.trigger,
            )}
          >
            <SelectPrimitive.Value
              className={cn("truncate", !hasValue && "text-muted", classNames?.value)}
            >
              {(selectedValue: string | string[] | null) => {
                if (
                  !selectedValue ||
                  (Array.isArray(selectedValue) && selectedValue.length === 0)
                ) {
                  return placeholder;
                }
                const values = Array.isArray(selectedValue) ? selectedValue : [selectedValue];
                return values
                  .map((v) => items.find((item) => item.value === v)?.label ?? v)
                  .join(", ");
              }}
            </SelectPrimitive.Value>

            <div className="flex items-center gap-1 shrink-0">
              {isClearable && hasValue && (
                <span
                  role="button"
                  tabIndex={-1}
                  aria-label="Clear selection"
                  onPointerDown={(event) => {
                    event.stopPropagation();
                    event.preventDefault();
                    onValueChange?.(isMultiple ? [] : null);
                  }}
                  className="rounded-full p-0.5 text-muted hover:text-foreground"
                >
                  <X className="size-3.5" />
                </span>
              )}
              <SelectPrimitive.Icon>
                <ChevronDown className="text-muted transition-transform duration-150 data-open:rotate-180" />
              </SelectPrimitive.Icon>
            </div>
          </SelectPrimitive.Trigger>

          <SelectPrimitive.Portal>
            <SelectPrimitive.Positioner
              side={side}
              align={align}
              sideOffset={sideOffset}
              alignItemWithTrigger={false}
            >
              <SelectPrimitive.Popup className={cn(selectPopupVariants, classNames?.popup)}>
                <SelectPrimitive.List>
                  {items.map((item) => (
                    <SelectPrimitive.Item
                      key={item.value}
                      value={item.value}
                      disabled={item.isDisabled}
                      className={cn(selectItemVariants, classNames?.item)}
                    >
                      <div className="flex flex-col min-w-0">
                        <span className="truncate">{item.label}</span>
                        {item.description && (
                          <span className="text-xs text-muted truncate">{item.description}</span>
                        )}
                      </div>
                      <SelectPrimitive.ItemIndicator>
                        <Check className="size-4 text-primary-600 dark:text-primary-400" />
                      </SelectPrimitive.ItemIndicator>
                    </SelectPrimitive.Item>
                  ))}
                </SelectPrimitive.List>
              </SelectPrimitive.Popup>
            </SelectPrimitive.Positioner>
          </SelectPrimitive.Portal>
        </SelectPrimitive.Root>

        {description && !isInvalid && (
          <Field.Description className={cn("text-xs text-muted", classNames?.description)}>
            {description}
          </Field.Description>
        )}

        <Field.Error
          match={isInvalid}
          className={cn("text-xs text-danger-600 dark:text-danger-500", classNames?.errorMessage)}
        >
          {errorMessage}
        </Field.Error>
      </Field.Root>
    );
  },
);

Select.displayName = "Select";

import { cva } from "class-variance-authority";
import { colorFocusRingClass } from "../../lib/color-focus-ring";

export const selectTriggerVariants = cva(
  "peer inline-flex w-full items-center justify-between gap-2 border bg-transparent text-left transition-[background-color,border-color,box-shadow] duration-200 outline-none focus-visible:ring-2 focus-visible:ring-offset-2 data-disabled:opacity-50 data-disabled:pointer-events-none data-readonly:cursor-default backdrop-blur-(--glass-blur) backdrop-saturate-(--glass-saturate)",
  {
    variants: {
      variant: {
        outline: "border-border bg-surface",
        solid: "border-transparent",
        soft: "border-transparent",
        ghost: "border-transparent bg-transparent",
      },
      color: {
        primary: "",
        secondary: "",
        neutral: "",
        success: "",
        warning: "",
        danger: "",
        info: "",
      },
      size: {
        xs: "h-8 px-3 text-xs [&_svg]:size-3.5",
        sm: "h-9 px-4 text-sm [&_svg]:size-3.5",
        md: "h-11 px-4 text-sm [&_svg]:size-4",
        lg: "h-12 px-5 text-base [&_svg]:size-4",
        xl: "h-14 px-6 text-lg [&_svg]:size-5",
      },
      radius: {
        sm: "rounded-sm",
        md: "rounded-md",
        lg: "rounded-lg",
        full: "rounded-full",
      },
      isInvalid: {
        true: "",
        false: "",
      },
    },
    compoundVariants: [
      { variant: "solid", color: "primary", class: "bg-neutral-100 dark:bg-neutral-800" },
      { variant: "solid", color: "secondary", class: "bg-neutral-100 dark:bg-neutral-800" },
      { variant: "solid", color: "neutral", class: "bg-neutral-100 dark:bg-neutral-800" },
      { variant: "solid", color: "success", class: "bg-neutral-100 dark:bg-neutral-800" },
      { variant: "solid", color: "warning", class: "bg-neutral-100 dark:bg-neutral-800" },
      { variant: "solid", color: "danger", class: "bg-neutral-100 dark:bg-neutral-800" },
      { variant: "solid", color: "info", class: "bg-neutral-100 dark:bg-neutral-800" },

      { variant: "soft", color: "primary", class: "bg-primary-500/10" },
      { variant: "soft", color: "secondary", class: "bg-secondary-500/10" },
      { variant: "soft", color: "neutral", class: "bg-neutral-500/10" },
      { variant: "soft", color: "success", class: "bg-success-500/10" },
      { variant: "soft", color: "warning", class: "bg-warning-500/10" },
      { variant: "soft", color: "danger", class: "bg-danger-500/10" },
      { variant: "soft", color: "info", class: "bg-info-500/10" },

      ...Object.entries(colorFocusRingClass).map(([color, ringClass]) => ({
        color: color as keyof typeof colorFocusRingClass,
        class: ringClass,
      })),
      {
        isInvalid: true,
        class: "border-danger-500 focus-visible:ring-danger-500",
      },
    ],
    defaultVariants: {
      variant: "outline",
      color: "primary",
      size: "md",
      radius: "lg",
      isInvalid: false,
    },
  },
);

export const selectPopupVariants =
  "z-50 max-h-(--available-height) w-(--anchor-width) overflow-y-auto rounded-lg border border-border bg-surface p-1 shadow-lg outline-none backdrop-blur-(--glass-blur) backdrop-saturate-(--glass-saturate) data-[starting-style]:opacity-0 data-[starting-style]:scale-95 data-[ending-style]:opacity-0 data-[ending-style]:scale-95 transition-[opacity,transform] duration-150 ease-(--ease-spring) motion-reduce:transition-none";

export const selectItemVariants =
  "relative flex cursor-pointer select-none items-center justify-between gap-2 rounded-md px-3 py-2 text-sm outline-none data-highlighted:bg-primary-500/10 data-disabled:opacity-50 data-disabled:pointer-events-none data-selected:font-semibold";
